mapper.select:
/* com.erns.coching.cochingtv.mapper.CochingtvDAO.getList */
SELECT ZZ.* FROM ( SELECT
FROM T_CH_TV AA
AND AA.DEL_YN = 'N'
ORDER BY AA.SORT_ORD ASC
) ZZ

/* com.erns.coching.cochingtv.mapper.CochingtvDAO.load */

SELECT

FROM T_CH_TV AA			

	AND AA.TV_SEQ = #{tvSeq, jdbcType=INTEGER}

mapper.insert:
/* com.erns.coching.cochingtv.mapper.CochingtvDAO.insert */


	SELECT nextval('seq_t_ch_tv')


INSERT INTO T_CH_TV (
    TV_SEQ
    , YT_URL
    , SORT_ORD
    , TITLE
    , HASHTAG
    , VIEWS
    , YT_DTTM
    , USE_YN
    , DEL_YN
    , CONTENT
    , RGTR
    , RGT_DTTM
    , CHNR
    , CHNG_DTTM
    , CATEGORY
) VALUES (
    #{tvSeq        , jdbcType=INTEGER}
    , #{ytUrl      , jdbcType=VARCHAR}
    , -1
    , #{title      , jdbcType=VARCHAR}
    , #{hashtag    , jdbcType=VARCHAR}
    , #{views      , jdbcType=VARCHAR}
    , #{ytDttm     , jdbcType=VARCHAR}
    , COALESCE(#{useYn  , jdbcType=CHAR}, 'Y')
    , COALESCE(#{delYn  , jdbcType=CHAR}, 'N')
    , #{content     , jdbcType=VARCHAR}
    , #{rgtr       , jdbcType=INTEGER}
    , now()
    , #{chnr       , jdbcType=INTEGER}
    , now()
    , #{category      , jdbcType=VARCHAR}
)

mapper.update:
	/* com.erns.coching.cochingtv.mapper.CochingtvDAO.updateState */

    UPDATE T_CH_TV SET
        YT_URL           = #{ytUrl    , jdbcType=VARCHAR}
        , TITLE             = #{title    , jdbcType=VARCHAR}
        , HASHTAG             = #{hashtag    , jdbcType=VARCHAR}
        , VIEWS           = #{views    , jdbcType=VARCHAR}
        , YT_DTTM           = #{ytDttm    , jdbcType=VARCHAR}
        , USE_YN           = COALESCE(#{useYn    , jdbcType=CHAR}, 'N')
		, CONTENT           = #{content    , jdbcType=VARCHAR}

        , CATEGORY           = #{category    , jdbcType=VARCHAR}

        , CHNR             = #{chnr     , jdbcType=INTEGER}
        , CHNG_DTTM        = now()

        AND TV_SEQ         = #{tvSeq    , jdbcType=INTEGER}

	/* com.erns.coching.cochingtv.mapper.CochingtvDAO.updateDelYn */

    UPDATE T_CH_TV SET
          DEL_YN            = COALESCE(#{delYn, jdbcType=CHAR}, 'N')

        , CHNR             = #{chnr     , jdbcType=INTEGER}
        , CHNG_DTTM        = now()

        AND TV_SEQ         = #{tvSeq    , jdbcType=INTEGER}

	/* com.erns.coching.cochingtv.mapper.CochingtvDAO.updateOrder */

    UPDATE T_CH_TV SET
          SORT_ORD      = #{sortOrd	, jdbcType=INTEGER}

        , CHNR             = #{chnr     , jdbcType=INTEGER}
        , CHNG_DTTM        = now()

        AND TV_SEQ         = #{tvSeq    , jdbcType=INTEGER}
